document.addEventListener('DOMContentLoaded',()=>{const inputs=document.querySelectorAll('input, select, textarea');inputs.forEach(input=>{input.addEventListener('focus',()=>{const label=input.parentElement.querySelector('label');if(label)label.classList.add('text-secondary');});input.addEventListener('blur',()=>{const label=input.parentElement.querySelector('label');if(label)label.classList.remove('text-secondary');});});});;